-- ============================================================================
-- Quiz Seed: Luke — Part 2 (Chapters 7–12)
-- 3 difficulties × 6 chapters = 96 total questions
--   kids:   3 per chapter  = 18
--   teens:  5 per chapter  = 30
--   adults: 8 per chapter  = 48
-- ============================================================================

-- ═══════════════ CHAPTERS 7–9 ═══════════════

-- ═══ Luke Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 7, 'kids', 1, 'What Roman soldier asked Jesus to heal his servant?', 'A centurion — a Roman officer with great faith', 'A general who was Jesus'' friend', 'A soldier who did not believe in God', 'A Roman governor named Pilate', 'a', 'Luke 7:2-3 — "And a certain centurion''s servant, who was dear unto him, was sick, and ready to die. And when he heard of Jesus, he sent unto him the elders of the Jews, beseeching him that he would come and heal his servant."'),
('Luke', 7, 'kids', 2, 'What happened when Jesus met a funeral procession in the town of Nain?', 'He raised the widow''s dead son back to life', 'He walked past without stopping', 'He told the people not to cry', 'He went to a different town', 'a', 'Luke 7:14-15 — "And he came and touched the bier: and they that bare him stood still. And he said, Young man, I say unto thee, Arise. And he that was dead sat up, and began to speak."'),
('Luke', 7, 'kids', 3, 'What did a woman do to show her love for Jesus at a Pharisee''s house?', 'She washed His feet with her tears and wiped them with her hair', 'She cooked Him a big dinner', 'She gave Him a golden crown', 'She sang a song for Him', 'a', 'Luke 7:38 — "And stood at his feet behind him weeping, and began to wash his feet with tears, and did wipe them with the hairs of her head, and kissed his feet, and anointed them with the ointment."'),
-- Teens
('Luke', 7, 'teens', 1, 'Why was Jesus amazed at the centurion?', 'He had not found so great faith, no, not in Israel — the centurion believed Jesus could heal with just a word', 'The centurion was very wealthy', 'The centurion had built a synagogue', 'The centurion knew many languages', 'a', 'Luke 7:9 — "When Jesus heard these things, he marvelled at him, and turned him about, and said unto the people that followed him, I say unto you, I have not found so great faith, no, not in Israel."'),
('Luke', 7, 'teens', 2, 'What question did John the Baptist send his disciples to ask Jesus from prison?', 'Art thou he that should come? or look we for another?', 'When will you free me from prison?', 'Why have you forgotten about me?', 'Will you become the king of Israel now?', 'a', 'Luke 7:19 — "And John calling unto him two of his disciples sent them to Jesus, saying, Art thou he that should come? or look we for another?"'),
('Luke', 7, 'teens', 3, 'How did Jesus answer John''s question about whether He was the Messiah?', 'He pointed to His works — the blind see, the lame walk, the lepers are cleansed, the deaf hear, the dead are raised, the poor hear the gospel', 'He said yes with a simple one-word answer', 'He refused to answer the question', 'He sent John a written letter', 'a', 'Luke 7:22 — "Go your way, and tell John what things ye have seen and heard; how that the blind see, the lame walk, the lepers are cleansed, the deaf hear, the dead are raised, to the poor the gospel is preached."'),
('Luke', 7, 'teens', 4, 'What parable did Jesus tell Simon the Pharisee about two debtors?', 'One owed 500 pence and the other 50; when both were forgiven, the one forgiven more loved the creditor more — illustrating why the sinful woman loved Jesus so greatly', 'One debtor paid and the other did not', 'Both debtors refused to repay', 'The creditor punished both equally', 'a', 'Luke 7:41-43 — "There was a certain creditor which had two debtors: the one owed five hundred pence, and the other fifty. And when they had nothing to pay, he frankly forgave them both. Tell me therefore, which of them will love him most?"'),
('Luke', 7, 'teens', 5, 'What did Jesus say to the sinful woman who anointed His feet?', 'Thy sins are forgiven... Thy faith hath saved thee; go in peace', 'You must first prove you are worthy', 'Go and sin no more before I forgive you', 'I cannot forgive you here', 'a', 'Luke 7:48,50 — "And he said unto her, Thy sins are forgiven... And he said to the woman, Thy faith hath saved thee; go in peace."'),
-- Adults
('Luke', 7, 'adults', 1, 'What does the centurion''s reasoning about authority reveal about his understanding of Jesus?', 'He understood that just as he gave commands under Roman authority and was obeyed, Jesus could command sickness with divine authority and be obeyed — recognising Jesus'' supernatural jurisdiction over disease', 'He thought Jesus needed to be physically present', 'He believed healing required a ritual', 'He thought Jesus was merely a good doctor', 'a', 'Luke 7:7-8 — "But say in a word, and my servant shall be healed. For I also am a man set under authority, having under me soldiers, and I say unto one, Go, and he goeth." The centurion''s military analogy shows he grasped Jesus'' delegated divine authority.'),
('Luke', 7, 'adults', 2, 'How does the raising of the widow''s son at Nain echo Old Testament miracles?', 'It directly parallels Elijah raising the widow''s son at Zarephath (1 Kings 17:17-24) — Luke intentionally draws this parallel, as the crowd responds: "A great prophet is risen up among us; God hath visited his people"', 'There is no Old Testament parallel', 'It mirrors Moses parting the Red Sea', 'It resembles David defeating Goliath', 'a', 'Luke 7:15-16 — "And he delivered him to his mother" echoes 1 Kings 17:23 ("and delivered him unto his mother"). The crowd''s response — "a great prophet" — shows they recognise the Elijah typology.'),
('Luke', 7, 'adults', 3, 'What is the significance of Jesus'' answer to John the Baptist in relation to Isaiah''s prophecies?', 'Jesus'' reply directly cites Isaiah 35:5-6 and 61:1 — miracles of healing and gospel preaching that Isaiah prophesied the Messiah would perform, giving John evidence to confirm Jesus'' identity from Scripture', 'Jesus was simply listing His daily activities', 'The answer had no connection to Old Testament prophecy', 'Jesus was avoiding the question', 'a', 'Luke 7:22 — Jesus''  answer combines Isaiah 35:5-6 (blind see, lame walk, deaf hear) with Isaiah 61:1 (gospel to the poor), inviting John to see messianic prophecy fulfilled before his disciples'' eyes.'),
('Luke', 7, 'adults', 4, 'What does Jesus mean by "Blessed is he, whosoever shall not be offended in me"?', 'Those who do not stumble over Jesus'' unexpected methods — His messiahship does not match political expectations, and blessed are those who accept God''s plan even when it differs from their own', 'No one has ever been offended by Jesus', 'Jesus was warning people to be polite', 'Jesus was predicting that no one would reject Him', 'a', 'Luke 7:23 — "And blessed is he, whosoever shall not be offended in me." The Greek "skandalizo" means to stumble. John expected a judging Messiah (3:17) but Jesus came in mercy. The blessing is on those who accept this.'),
('Luke', 7, 'adults', 5, 'What does Jesus say about John the Baptist''s role in the history of redemption?', 'Among those born of women there is not a greater prophet than John the Baptist — yet the least in the kingdom of God is greater than he, because the kingdom era surpasses the prophetic era', 'John was an ordinary prophet', 'John was less important than Moses', 'John was greater than Jesus', 'a', 'Luke 7:28 — "For I say unto you, Among those that are born of women there is not a greater prophet than John the Baptist: but he that is least in the kingdom of God is greater than he." John was the greatest of the old order; the least in the new kingdom surpasses him positionally.'),
('Luke', 7, 'adults', 6, 'What does the contrast between Simon the Pharisee and the sinful woman teach about the relationship between forgiveness and love?', 'The one who is forgiven much loves much — the woman''s extravagant devotion flowed from her awareness of being greatly forgiven, while Simon''s coldness reflected his failure to recognise his own need for forgiveness', 'Simon was more righteous than the woman', 'The woman was trying to earn forgiveness by her actions', 'Love must come before forgiveness', 'a', 'Luke 7:47 — "Her sins, which are many, are forgiven; for she loved much: but to whom little is forgiven, the same loveth little." The love is the evidence of forgiveness already received, not the cause of it.'),
('Luke', 7, 'adults', 7, 'What does the dinner guests'' question "Who is this that forgiveth sins also?" reveal?', 'They correctly understood that forgiving sins is a divine prerogative — their question is Christological, recognising that Jesus'' claim to forgive implies a claim to deity', 'They were asking a trivial social question', 'They already knew the answer', 'They were trying to be polite', 'a', 'Luke 7:49 — "And they that sat at meat with him began to say within themselves, Who is this that forgiveth sins also?" Their reaction echoes 5:21 and shows that Jesus'' forgiveness claims raised the question of His identity repeatedly.'),
('Luke', 7, 'adults', 8, 'How does Jesus'' characterisation of "this generation" as children in the marketplace illustrate Israel''s rejection?', 'They are like children who refuse to play whether the music is happy or sad — they rejected John for his asceticism and Jesus for His sociability, showing that the real issue was their unwillingness to repent, not the messenger''s style', 'The children represent the disciples', 'Jesus was describing innocent children at play', 'The marketplace represents the temple', 'a', 'Luke 7:31-35 — "They are like unto children sitting in the marketplace... We have piped unto you, and ye have not danced; we have mourned to you, and ye have not wept." No style of ministry satisfied them — the problem was hardened hearts, not methods.');

-- ═══ Luke Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 8, 'kids', 1, 'In the parable of the sower, what does the good ground represent?', 'People who hear God''s word, keep it, and bring forth fruit', 'People who never listen at all', 'People who plant flowers', 'People who have big gardens', 'a', 'Luke 8:15 — "But that on the good ground are they, which in an honest and good heart, having heard the word, keep it, and bring forth fruit with patience."'),
('Luke', 8, 'kids', 2, 'What did Jesus do when a big storm came while they were in a boat?', 'He rebuked the wind and the raging water, and they stopped', 'He swam to shore', 'He asked the disciples to row faster', 'He built a bigger boat', 'a', 'Luke 8:24 — "And they came to him, and awoke him, saying, Master, master, we perish. Then he arose, and rebuked the wind and the raging of the water: and they ceased, and there was a calm."'),
('Luke', 8, 'kids', 3, 'What did the man with many demons say his name was?', 'Legion, because many devils had entered him', 'David', 'Peter', 'Samuel', 'a', 'Luke 8:30 — "And Jesus asked him, saying, What is thy name? And he said, Legion: because many devils were entered into him."'),
-- Teens
('Luke', 8, 'teens', 1, 'In the parable of the sower, what do the thorns represent?', 'Cares, riches, and pleasures of this life which choke the word and prevent it from bearing fruit', 'Good soil that helps plants grow', 'Birds that eat the seed', 'Rocks that block the sun', 'a', 'Luke 8:14 — "And that which fell among thorns are they, which, when they have heard, go forth, and are choked with cares and riches and pleasures of this life, and bring no fruit to perfection."'),
('Luke', 8, 'teens', 2, 'What did Jesus say to the disciples after calming the storm?', 'Where is your faith? — and the disciples asked one another, What manner of man is this! for he commandeth even the winds and water, and they obey him', 'You should have calmed the storm yourselves', 'This storm was not dangerous at all', 'You should have stayed on shore', 'a', 'Luke 8:25 — "And he said unto them, Where is your faith? And they being afraid wondered, saying one to another, What manner of man is this! for he commandeth even the winds and water, and they obey him."'),
('Luke', 8, 'teens', 3, 'What happened to the woman who had been bleeding for twelve years when she touched Jesus'' garment?', 'Her flow of blood stopped immediately — and Jesus said, Thy faith hath made thee whole; go in peace', 'She had to wait three more days to be healed', 'Nothing happened at first', 'Jesus did not notice her', 'a', 'Luke 8:44,48 — "She came behind him, and touched the border of his garment: and immediately her issue of blood stanched... Daughter, be of good comfort: thy faith hath made thee whole; go in peace."'),
('Luke', 8, 'teens', 4, 'What did Jesus say when people laughed at Him for saying Jairus'' daughter was not dead but sleeping?', 'He put them all out, then took her by the hand and called, Maid, arise — and her spirit came again and she arose straightway', 'He agreed that she was dead and left', 'He got angry and refused to help', 'He waited until the mourners finished', 'a', 'Luke 8:54-55 — "And he put them all out, and took her by the hand, and called, saying, Maid, arise. And her spirit came again, and she arose straightway: and he commanded to give her meat."'),
('Luke', 8, 'teens', 5, 'What did the healed demoniac want to do, and what did Jesus tell him instead?', 'He wanted to stay with Jesus, but Jesus told him to return home and tell what great things God had done for him', 'He wanted to go away to another country', 'He wanted to become a fisherman', 'He wanted to go to the temple in Jerusalem', 'a', 'Luke 8:38-39 — "Now the man out of whom the devils were departed besought him that he might be with him: but Jesus sent him away, saying, Return to thine own house, and shew how great things God hath done unto thee."'),
-- Adults
('Luke', 8, 'adults', 1, 'What is the purpose of parables according to Jesus'' explanation in verses 9-10?', 'To reveal truth to receptive hearts while concealing it from those who refuse to understand — "Unto you it is given to know the mysteries of the kingdom of God: but to others in parables; that seeing they might not see, and hearing they might not understand"', 'To make teaching easier for everyone', 'To entertain the crowds', 'To avoid controversial topics', 'a', 'Luke 8:10 — Jesus quotes Isaiah 6:9, explaining that parables function as both revelation and judgment — illuminating the willing and hardening the unwilling. This is a gracious judgment: light increases sight for those who see and blinds those who close their eyes.'),
('Luke', 8, 'adults', 2, 'What four soil types in the parable represent four responses to God''s word?', 'Wayside (hard hearts, devil snatches the word), rock (superficial faith, no root in testing), thorns (choked by cares, riches, pleasures), good ground (honest hearts who bear fruit with patience)', 'Four types of farming methods', 'Four different crops', 'Four seasons of the year', 'a', 'Luke 8:12-15 — The four soils represent a spectrum of receptivity. Only the last brings forth fruit "with patience" — genuine faith endures testing, resists worldly distraction, and produces lasting results.'),
('Luke', 8, 'adults', 3, 'What does Jesus'' authority over the storm reveal about His nature?', 'Power over creation belongs to God alone (cf. Psalm 107:29, Job 38:8-11) — by calming the sea with a command, Jesus demonstrates divine sovereignty over nature, prompting the Christological question: "What manner of man is this?"', 'Jesus was a skilled sailor', 'It was a coincidence that the storm stopped', 'Jesus had natural weather knowledge', 'a', 'Luke 8:24-25 — "He arose, and rebuked the wind and the raging of the water: and they ceased." The OT consistently attributes mastery over seas and storms to YHWH alone. The disciples'' astonishment is the right theological response.'),
('Luke', 8, 'adults', 4, 'What is the significance of the name "Legion" in the Gadarene demoniac account?', 'A Roman legion comprised 5,000-6,000 soldiers — the name indicates massive demonic possession, yet even this army of demons was subject to Jesus'' authority and had to beg His permission before entering the swine', 'It was the man''s family name', 'It was a common name in that region', 'It referred to a local military unit', 'a', 'Luke 8:30 — "Legion: because many devils were entered into him." The military metaphor emphasises both the magnitude of demonic bondage and the superiority of Christ''s authority — He single-handedly routes an entire demonic army.'),
('Luke', 8, 'adults', 5, 'Why did the Gadarenes ask Jesus to depart after the demoniac was healed?', 'They were seized with great fear — the economic loss of the swine herd and the display of supernatural power frightened them more than the demoniac had, revealing that they valued their livelihood over liberation from evil', 'They were happy and wanted to celebrate alone', 'They had other business to attend to', 'Jesus asked to leave first', 'a', 'Luke 8:37 — "Then the whole multitude of the country of the Gadarenes round about besought him to depart from them; for they were taken with great fear." Fear of divine power, combined with economic concern, led them to reject the very one who could save them.'),
('Luke', 8, 'adults', 6, 'What does the raising of Jairus'' daughter alongside the healing of the woman with the issue of blood demonstrate about Jesus'' power?', 'Jesus'' power is comprehensive — He can heal a chronic condition (12-year illness) and conquer death itself, and both miracles respond to faith, showing that no situation is beyond His ability', 'These are unrelated stories placed together randomly', 'Only one miracle actually happened', 'Jesus could heal illness but not raise the dead', 'a', 'Luke 8:43-55 — The intercalation (story-within-a-story) structure links these miracles: both involve 12 years (the woman''s illness and the girl''s age), both require faith, and together they show Jesus'' authority over chronic disease and death itself.'),
('Luke', 8, 'adults', 7, 'What does "No man, when he hath lighted a candle, covereth it with a vessel" teach about discipleship?', 'Truth received must be shared openly — disciples are not to hide the mysteries of the kingdom but let them shine, because everything hidden will ultimately be revealed', 'Candles should be stored carefully', 'Only priests can teach spiritual truths', 'Knowledge should be kept secret forever', 'a', 'Luke 8:16-17 — "No man, when he hath lighted a candle, covereth it with a vessel, or putteth it under a bed; but setteth it on a candlestick, that they which enter in may see the light. For nothing is secret, that shall not be made manifest."'),
('Luke', 8, 'adults', 8, 'What does Jesus'' statement "My mother and my brethren are these which hear the word of God, and do it" redefine?', 'It redefines family in spiritual terms — biological kinship is secondary to the bond formed by hearing and obeying God''s word, establishing the community of faith as the true family of God', 'Jesus was rejecting His biological family', 'Jesus did not love His mother', 'Family relationships have no value at all', 'a', 'Luke 8:21 — "My mother and my brethren are these which hear the word of God, and do it." Jesus does not dishonour His family but elevates spiritual kinship through obedience above biological ties (cf. Luke 11:28).');

-- ═══════════════ CHAPTERS 10–12 ═══════════════

-- ═══ Luke Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 9, 'kids', 1, 'How many people did Jesus feed with five loaves and two fishes?', 'About five thousand men, plus women and children', 'About fifty people', 'About five hundred people', 'Only the twelve disciples', 'a', 'Luke 9:14,16-17 — "For they were about five thousand men... Then he took the five loaves and the two fishes, and looking up to heaven, he blessed them... And they did eat, and were all filled."'),
('Luke', 9, 'kids', 2, 'What happened to Jesus on the mountain when He was praying?', 'His face and clothes became shining white — He was transfigured', 'He fell asleep on the mountain', 'A rainbow appeared over His head', 'He found a treasure hidden in a cave', 'a', 'Luke 9:29 — "And as he prayed, the fashion of his countenance was altered, and his raiment was white and glistering."'),
('Luke', 9, 'kids', 3, 'Who did Peter say Jesus was?', 'The Christ of God — the promised Messiah', 'A great teacher only', 'One of the old prophets', 'John the Baptist come back', 'a', 'Luke 9:20 — "He said unto them, But whom say ye that I am? Peter answering said, The Christ of God."'),
-- Teens
('Luke', 9, 'teens', 1, 'What did Jesus say a person must do to follow Him?', 'Deny himself, take up his cross daily, and follow me', 'Bring a large donation of money', 'First finish all worldly business', 'Memorise the entire Old Testament', 'a', 'Luke 9:23 — "And he said to them all, If any man will come after me, let him deny himself, and take up his cross daily, and follow me."'),
('Luke', 9, 'teens', 2, 'What did Jesus say about saving and losing your life?', 'Whosoever will save his life shall lose it: but whosoever will lose his life for my sake, the same shall save it', 'Save your life at all costs', 'Your physical life is all that matters', 'Losing your life means losing everything', 'a', 'Luke 9:24 — "For whosoever will save his life shall lose it: but whosoever will lose his life for my sake, the same shall save it."'),
('Luke', 9, 'teens', 3, 'Who appeared with Jesus at the Transfiguration?', 'Moses and Elias (Elijah), who spoke with Him about His departure which He would accomplish at Jerusalem', 'Abraham and Isaac', 'David and Solomon', 'Adam and Noah', 'a', 'Luke 9:30-31 — "And, behold, there talked with him two men, which were Moses and Elias: Who appeared in glory, and spake of his decease which he should accomplish at Jerusalem."'),
('Luke', 9, 'teens', 4, 'What did the voice from the cloud say at the Transfiguration?', 'This is my beloved Son: hear him', 'This is a great prophet among you', 'This is the king of Israel', 'This is the angel of the Lord', 'a', 'Luke 9:35 — "And there came a voice out of the cloud, saying, This is my beloved Son: hear him."'),
('Luke', 9, 'teens', 5, 'What did Jesus say about the person who looks back after putting his hand to the plough?', 'No man, having put his hand to the plough, and looking back, is fit for the kingdom of God', 'Looking back is perfectly fine', 'Only farmers need to worry about this', 'Ploughing has nothing to do with following God', 'a', 'Luke 9:62 — "And Jesus said unto him, No man, having put his hand to the plough, and looking back, is fit for the kingdom of God."'),
-- Adults
('Luke', 9, 'adults', 1, 'What does the feeding of the five thousand reveal about Jesus in relation to Old Testament typology?', 'Jesus acts as the new Moses who feeds God''s people in the wilderness — and as the true Shepherd of Israel (Psalm 23, Ezekiel 34) who provides abundantly, with twelve baskets remaining (one for each tribe)', 'It was simply a picnic', 'Jesus was teaching cooking skills', 'It was a normal meal with no deeper meaning', 'a', 'Luke 9:16-17 — The miracle echoes God feeding Israel with manna (Exodus 16) and Elisha''s multiplication (2 Kings 4:42-44). The twelve baskets of surplus symbolise God''s provision for all Israel.'),
('Luke', 9, 'adults', 2, 'Why did Moses and Elijah appear at the Transfiguration, and what is the significance of their topic of conversation?', 'Moses represents the Law and Elijah the Prophets — both witnessing to Christ. They spoke of His "decease" (Greek: exodus) at Jerusalem, connecting the cross to Israel''s founding deliverance from Egypt', 'They appeared to congratulate Jesus', 'They came to give Jesus new commandments', 'It was a random supernatural event', 'a', 'Luke 9:31 — "Who appeared in glory, and spake of his decease which he should accomplish at Jerusalem." Luke uniquely uses "exodus" (departure), linking Jesus'' death to the original Exodus — a greater deliverance from sin.'),
('Luke', 9, 'adults', 3, 'What is the theological meaning of "take up his cross daily"?', 'Daily self-denial and willingness to suffer for Christ — the cross was not a metaphor for minor inconvenience but an instrument of execution, meaning radical surrender of self-will to God''s purposes', 'Wearing a cross necklace every day', 'Carrying a literal wooden cross', 'Going to church on Sundays', 'a', 'Luke 9:23 — "Let him deny himself, and take up his cross daily, and follow me." Luke alone adds "daily," making it a continuous, repeated act of self-surrender rather than a single dramatic event.'),
('Luke', 9, 'adults', 4, 'What does "For what is a man advantaged, if he gain the whole world, and lose himself, or be cast away?" teach about priorities?', 'No earthly gain can compensate for the loss of one''s soul — the exchange rate between the world and the soul is infinite, making self-preservation at the cost of faithfulness the worst possible bargain', 'Gaining wealth is always wrong', 'The world has no value at all', 'This only applies to wealthy people', 'a', 'Luke 9:25 — "For what is a man advantaged, if he gain the whole world, and lose himself, or be cast away?" The rhetorical question exposes the folly of trading eternal life for temporal gain.'),
('Luke', 9, 'adults', 5, 'What is significant about Luke 9:51 — "he stedfastly set his face to go to Jerusalem"?', 'It marks the beginning of Luke''s extensive travel narrative (9:51–19:27) — Jesus deliberately and resolutely turns toward Jerusalem and the cross, showing His death was not an accident but a purposeful journey toward the Father''s will', 'Jesus was going to Jerusalem for a festival', 'Jesus was looking for a place to rest', 'Jesus was fleeing from Herod', 'a', 'Luke 9:51 — "And it came to pass, when the time was come that he should be received up, he stedfastly set his face to go to Jerusalem." This pivotal verse introduces the journey motif unique to Luke, comprising nearly ten chapters.'),
('Luke', 9, 'adults', 6, 'Why did Jesus rebuke James and John for wanting to call down fire on the Samaritan village?', 'Their desire for destruction contradicted Jesus'' mission — "The Son of man is not come to destroy men''s lives, but to save them," correcting their vengeful Elijah-like impulse with the spirit of the gospel', 'Jesus approved of their request', 'The Samaritans deserved destruction', 'James and John were completely right', 'a', 'Luke 9:55-56 — "But he turned, and rebuked them, and said, Ye know not what manner of spirit ye are of. For the Son of man is not come to destroy men''s lives, but to save them." Jesus corrects misguided zeal with mission clarity.'),
('Luke', 9, 'adults', 7, 'What three would-be followers does Jesus encounter in verses 57-62, and what does each exchange teach?', 'One offers eagerly (Jesus warns of homelessness); one is called but wants to bury his father (Jesus demands priority); one wants to say farewell first (Jesus warns against looking back) — total commitment with no conditions is required', 'All three followed Jesus immediately', 'Jesus rejected all three completely', 'Only the first one was worthy', 'a', 'Luke 9:57-62 — Three potential disciples illustrate obstacles: comfort (v.58), family obligations (v.59-60), and divided loyalty (v.61-62). Each exchange shows that discipleship demands unconditional, immediate, forward-looking commitment.'),
('Luke', 9, 'adults', 8, 'What is the messianic secret, and how does Luke 9:21 illustrate it?', 'Jesus "straitly charged them, and commanded them to tell no man" that He was the Christ — He controlled the revelation of His identity to prevent political messianic expectations that would undermine His mission of suffering before glory', 'Jesus was unsure of His identity', 'Peter was wrong about Jesus being the Christ', 'Jesus wanted to avoid all public attention permanently', 'a', 'Luke 9:21-22 — Jesus immediately follows Peter''s confession with a passion prediction: the Christ must suffer, be rejected, be killed, and rise. He silences premature proclamation because the cross must precede the crown.');

-- ═══ Luke Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 10, 'kids', 1, 'In the story of the Good Samaritan, who stopped to help the hurt man?', 'A Samaritan — a man from a group the Jews did not like', 'A priest from the temple', 'A Levite who worked at the temple', 'A Roman soldier passing by', 'a', 'Luke 10:33 — "But a certain Samaritan, as he journeyed, came where he was: and when he saw him, he had compassion on him."'),
('Luke', 10, 'kids', 2, 'What two sisters did Jesus visit in their home?', 'Mary and Martha', 'Ruth and Naomi', 'Rachel and Leah', 'Sarah and Hagar', 'a', 'Luke 10:38-39 — "A certain woman named Martha received him into her house. And she had a sister called Mary, which also sat at Jesus'' feet, and heard his word."'),
('Luke', 10, 'kids', 3, 'What did Mary choose to do instead of helping Martha with the housework?', 'She sat at Jesus'' feet and listened to His word', 'She went shopping at the market', 'She took a nap in her room', 'She went to visit a friend', 'a', 'Luke 10:39 — "And she had a sister called Mary, which also sat at Jesus'' feet, and heard his word."'),
-- Teens
('Luke', 10, 'teens', 1, 'How many disciples did Jesus send out ahead of Him in pairs?', 'Seventy (some manuscripts say seventy-two)', 'Twelve', 'Seven', 'One hundred', 'a', 'Luke 10:1 — "After these things the Lord appointed other seventy also, and sent them two and two before his face into every city and place, whither he himself would come."'),
('Luke', 10, 'teens', 2, 'What did Jesus tell the seventy to rejoice about?', 'That their names are written in heaven — not that the spirits are subject to them', 'That they had performed many miracles', 'That they were famous among the people', 'That they had defeated all their enemies', 'a', 'Luke 10:20 — "Notwithstanding in this rejoice not, that the spirits are subject unto you; but rather rejoice, because your names are written in heaven."'),
('Luke', 10, 'teens', 3, 'What command summarises the whole law according to the lawyer''s answer?', 'Thou shalt love the Lord thy God with all thy heart, soul, strength, and mind; and thy neighbour as thyself', 'Thou shalt not steal or kill', 'Keep the Sabbath day holy', 'Pay your tithes faithfully', 'a', 'Luke 10:27 — "Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy strength, and with all thy mind; and thy neighbour as thyself."'),
('Luke', 10, 'teens', 4, 'In the Good Samaritan parable, who passed by the injured man without helping?', 'A priest and a Levite — both religious leaders who should have shown mercy', 'Two Roman soldiers', 'A group of merchants', 'The man''s own family members', 'a', 'Luke 10:31-32 — "And by chance there came down a certain priest that way: and when he saw him, he passed by on the other side. And likewise a Levite, when he was at the place, came and looked on him, and passed by on the other side."'),
('Luke', 10, 'teens', 5, 'What did Jesus say to Martha when she complained that Mary was not helping?', 'Martha, Martha, thou art careful and troubled about many things: but one thing is needful: and Mary hath chosen that good part, which shall not be taken away from her', 'Martha, you are right to be upset', 'Martha, tell Mary to come and help now', 'Martha, stop cooking and rest', 'a', 'Luke 10:41-42 — "And Jesus answered and said unto her, Martha, Martha, thou art careful and troubled about many things: But one thing is needful: and Mary hath chosen that good part, which shall not be taken away from her."'),
-- Adults
('Luke', 10, 'adults', 1, 'What is the theological significance of Jesus sending seventy disciples, not just twelve?', 'The seventy likely symbolise the seventy nations of Genesis 10 — foreshadowing the universal mission to all peoples, while the twelve represented the twelve tribes of Israel. Luke emphasises the gospel''s reach beyond Israel', 'It was simply because more workers were needed', 'Seventy was a random number', 'Jesus could not find enough qualified people for twelve', 'a', 'Luke 10:1 — The number seventy echoes the seventy nations in the Table of Nations (Genesis 10) and the seventy elders appointed by Moses (Numbers 11:16-17). Luke, writing for a Gentile audience, highlights the universal scope of Christ''s mission.'),
('Luke', 10, 'adults', 2, 'What does "I beheld Satan as lightning fall from heaven" mean in context?', 'As the seventy report victories over demons, Jesus sees the broader cosmic reality — Satan''s authority is being overthrown through the disciples'' ministry, anticipating the ultimate defeat of evil through the cross', 'Satan literally fell from the sky that day', 'Jesus was describing a past event with no present significance', 'It was a metaphor about weather', 'a', 'Luke 10:18 — "I beheld Satan as lightning fall from heaven." Jesus connects the disciples'' exorcisms to a cosmic defeat of Satan. The imperfect tense ("I was watching") suggests an ongoing process of Satan''s dethronement.'),
('Luke', 10, 'adults', 3, 'Why is the Good Samaritan parable so shocking in its original context?', 'Samaritans were despised by Jews as racial and religious half-breeds — making a Samaritan the hero while the priest and Levite (Israel''s religious elite) fail, overturns every expectation and redefines "neighbour" beyond ethnic boundaries', 'Samaritans were widely respected by Jews', 'The parable was not controversial at all', 'Priests always helped everyone in need', 'a', 'Luke 10:33-37 — The Samaritan-Jewish hostility (cf. John 4:9, Luke 9:53) makes this parable explosive. Jesus demolishes ethno-religious tribalism: true neighbour-love transcends all boundaries. The lawyer cannot even say "Samaritan," only "he that shewed mercy."'),
('Luke', 10, 'adults', 4, 'What is Jesus'' response "Go, and do thou likewise" demanding of the lawyer?', 'Practical, boundary-crossing compassion — not merely theological knowledge about who qualifies as a neighbour, but active mercy toward anyone in need, regardless of social, ethnic, or religious differences', 'The lawyer should become a Samaritan', 'The lawyer should travel the Jericho road', 'The lawyer should give up studying the law', 'a', 'Luke 10:37 — "Then said Jesus unto him, Go, and do thou likewise." The lawyer asked "Who is my neighbour?" (seeking to limit obligation). Jesus flips the question: "Which was neighbour?" — shifting from defining recipients to becoming an agent of mercy.'),
('Luke', 10, 'adults', 5, 'What does the Mary and Martha story teach about priorities in discipleship?', 'Sitting at Jesus'' feet to hear His word is "the one thing needful" and "the good part" — active service is valuable but must not crowd out devotion to Christ and His teaching, which is the foundation of all ministry', 'Martha''s approach was wrong and sinful', 'Housework should always be avoided', 'Christians should never serve others practically', 'a', 'Luke 10:42 — "One thing is needful: and Mary hath chosen that good part, which shall not be taken away from her." Jesus does not condemn service but corrects anxious busyness that displaces communion with Him.'),
('Luke', 10, 'adults', 6, 'What does Jesus'' prayer in verses 21-22 reveal about divine revelation?', 'God hides truth from the wise and prudent and reveals it to babes — salvation knowledge comes not through human intellect but through divine disclosure, and only the Son fully knows the Father', 'Only scholars can understand spiritual truth', 'Education is the key to knowing God', 'Human wisdom is sufficient for salvation', 'a', 'Luke 10:21-22 — "Thou hast hid these things from the wise and prudent, and hast revealed them unto babes... no man knoweth who the Son is, but the Father; and who the Father is, but the Son, and he to whom the Son will reveal him."'),
('Luke', 10, 'adults', 7, 'What Christological claim is embedded in verse 22?', 'Jesus claims exclusive mutual knowledge with the Father — "no man knoweth who the Son is, but the Father; and who the Father is, but the Son" — an extraordinary claim to unique divine relationship and authority as the sole mediator of knowledge of God', 'Jesus was simply a great teacher', 'Anyone can know God equally well', 'This verse makes no special claim about Jesus', 'a', 'Luke 10:22 — This verse, sometimes called the "Johannine thunderbolt" because it sounds like John''s Gospel, reveals the Son''s unique filial relationship with the Father and His exclusive role as revealer of God.'),
('Luke', 10, 'adults', 8, 'What does "Blessed are the eyes which see the things that ye see" tell the disciples about their privileged position?', 'They are witnessing what prophets and kings longed to see but could not — the fulfilment of messianic promises in their very presence, making them the most privileged generation in redemptive history', 'The disciples had better eyesight than others', 'All generations are equally blessed', 'This only applies to the seventy, not others', 'a', 'Luke 10:23-24 — "Blessed are the eyes which see the things that ye see: For I tell you, that many prophets and kings have desired to see those things which ye see, and have not seen them." The disciples witness the dawn of the messianic age.');

-- ═══ Luke Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 11, 'kids', 1, 'What prayer did Jesus teach His disciples?', 'The Lord''s Prayer — Our Father which art in heaven, Hallowed be thy name', 'A prayer about food and clothing', 'A prayer about becoming rich', 'A prayer about defeating enemies', 'a', 'Luke 11:2 — "And he said unto them, When ye pray, say, Our Father which art in heaven, Hallowed be thy name. Thy kingdom come. Thy will be done, as in heaven, so in earth."'),
('Luke', 11, 'kids', 2, 'What did Jesus say would happen if you ask, seek, and knock?', 'Ask and it shall be given you; seek and ye shall find; knock and it shall be opened unto you', 'Nothing will happen at all', 'You must wait a very long time', 'Only grown-ups can ask God for things', 'a', 'Luke 11:9 — "And I say unto you, Ask, and it shall be given you; seek, and ye shall find; knock, and it shall be opened unto you."'),
('Luke', 11, 'kids', 3, 'What good gift does the heavenly Father give to those who ask Him?', 'The Holy Spirit', 'Gold and silver', 'A big house', 'New clothes', 'a', 'Luke 11:13 — "If ye then, being evil, know how to give good gifts unto your children: how much more shall your heavenly Father give the Holy Spirit to them that ask him?"'),
-- Teens
('Luke', 11, 'teens', 1, 'What point did Jesus make with the parable of the friend at midnight?', 'Because of persistent asking (importunity), the friend will give what is needed — teaching that we should persist in prayer without giving up', 'Friends should never bother each other', 'Only ask God once and never again', 'Midnight prayers are more powerful', 'a', 'Luke 11:8 — "Though he will not rise and give him, because he is his friend, yet because of his importunity he will rise and give him as many as he needeth."'),
('Luke', 11, 'teens', 2, 'What did Jesus say about a kingdom divided against itself?', 'Every kingdom divided against itself is brought to desolation — He used this to refute the claim that He cast out devils by Beelzebub', 'Divided kingdoms are always stronger', 'Kingdoms never divide', 'Only earthly kingdoms can be divided', 'a', 'Luke 11:17 — "Every kingdom divided against itself is brought to desolation; and a house divided against a house falleth."'),
('Luke', 11, 'teens', 3, 'What did Jesus say is the only sign that would be given to that generation?', 'The sign of Jonas the prophet — as Jonah was a sign to the Ninevites, so shall the Son of man be to this generation', 'A star appearing in the sky', 'The temple being rebuilt', 'A military victory over Rome', 'a', 'Luke 11:29-30 — "This is an evil generation: they seek a sign; and there shall no sign be given it, but the sign of Jonas the prophet. For as Jonas was a sign unto the Ninevites, so shall also the Son of man be to this generation."'),
('Luke', 11, 'teens', 4, 'What did Jesus say about the Pharisees and their concern for outward cleanliness?', 'Ye Pharisees make clean the outside of the cup and platter, but your inward part is full of ravening and wickedness', 'The Pharisees were perfectly clean inside and outside', 'Outward cleanliness is all that matters', 'Jesus praised their washing habits', 'a', 'Luke 11:39 — "Now do ye Pharisees make clean the outside of the cup and the platter; but your inward part is full of ravening and wickedness."'),
('Luke', 11, 'teens', 5, 'Who did Jesus say are truly blessed?', 'Blessed are they that hear the word of God, and keep it', 'Blessed are those who are wealthy and powerful', 'Blessed are those who are famous', 'Blessed are those who never face difficulty', 'a', 'Luke 11:28 — "But he said, Yea rather, blessed are they that hear the word of God, and keep it."'),
-- Adults
('Luke', 11, 'adults', 1, 'How does Luke''s version of the Lord''s Prayer differ from Matthew''s, and what is significant?', 'Luke''s version is shorter and emphasises daily dependence ("give us day by day our daily bread") and the Holy Spirit as the gift of prayer (v.13) — whereas Matthew''s is more liturgical. Luke shows prayer as personal communion with a generous Father', 'They are identical', 'Luke''s version is much longer', 'Matthew did not include the Lord''s Prayer', 'a', 'Luke 11:2-4 — Luke''s shorter form may represent the prayer''s essence, while Matthew''s expanded version was used liturgically. Luke uniquely concludes the teaching with the promise of the Holy Spirit (v.13), the Father''s supreme gift.'),
('Luke', 11, 'adults', 2, 'What does the "finger of God" reference mean when Jesus says "I with the finger of God cast out devils"?', 'It alludes to Exodus 8:19 where the Egyptian magicians recognised God''s power — Jesus claims the same divine power that delivered Israel from Egypt is now active in His exorcisms, proving the kingdom of God has come', 'It refers to a magical technique', 'It means Jesus used physical force', 'It has no Old Testament background', 'a', 'Luke 11:20 — "But if I with the finger of God cast out devils, no doubt the kingdom of God is come upon you." Matthew 12:28 has "Spirit of God." Luke''s "finger of God" echoes Exodus 8:19, linking Jesus'' exorcisms to the Exodus deliverance.'),
('Luke', 11, 'adults', 3, 'What does the parable of the strong man and the stronger man teach about Jesus'' ministry?', 'Satan is the strong man guarding his palace; Jesus is the stronger one who overcomes him, takes away his armour, and divides his spoils — exorcisms are evidence of Satan''s defeat, not collusion with him', 'Satan and Jesus are equally powerful', 'The strong man represents the Roman Empire', 'Jesus was the strong man, not the stronger one', 'a', 'Luke 11:21-22 — "When a strong man armed keepeth his palace, his goods are in peace: But when a stronger than he shall come upon him, and overcome him, he taketh from him all his armour wherein he trusted, and divideth his spoils."'),
('Luke', 11, 'adults', 4, 'What does the sign of Jonah mean in Luke''s context?', 'Just as Jonah''s preaching was itself the sign to Nineveh (not the fish episode), so Jesus'' preaching and person are the sign to this generation — if they reject the greater-than-Jonah, their judgment will be more severe', 'Jonah and Jesus both spent time inside a fish', 'The sign was about going on a sea voyage', 'There is no connection between Jonah and Jesus', 'a', 'Luke 11:30,32 — "For as Jonas was a sign unto the Ninevites, so shall also the Son of man be to this generation... The men of Nineve shall rise up in the judgment with this generation, and shall condemn it: for they repented at the preaching of Jonas; and, behold, a greater than Jonas is here."'),
('Luke', 11, 'adults', 5, 'What does Jesus'' woe against the lawyers for taking away "the key of knowledge" mean?', 'The religious experts had so distorted Scripture with their traditions that they prevented people from understanding God''s truth — they neither entered the kingdom themselves nor allowed others to enter', 'Lawyers had stolen physical keys from the temple', 'Education in general was being criticised', 'Only lawyers could understand the Bible', 'a', 'Luke 11:52 — "Woe unto you, lawyers! for ye have taken away the key of knowledge: ye entered not in yourselves, and them that were entering in ye hindered." The "key of knowledge" is the correct interpretation of Scripture that opens the door to God''s kingdom.'),
('Luke', 11, 'adults', 6, 'What does the warning about the unclean spirit returning with seven others teach?', 'Mere moral reform without being filled with God''s presence leaves a person worse off — the empty, swept house represents a life cleansed of evil but not filled with good, making it vulnerable to worse spiritual bondage', 'Demons always travel in groups of seven', 'Houses should never be cleaned', 'This parable is about hygiene practices', 'a', 'Luke 11:24-26 — "Then goeth he, and taketh to him seven other spirits more wicked than himself; and they enter in, and dwell there: and the last state of that man is worse than the first." Spiritual vacuum invites worse occupation.'),
('Luke', 11, 'adults', 7, 'What did Jesus mean by "the queen of the south shall rise up in the judgment with the men of this generation"?', 'The Queen of Sheba, a Gentile, will condemn Israel because she travelled far to hear Solomon''s wisdom, yet Israel rejects one greater than Solomon standing in their midst — judgment is proportional to privilege', 'The queen will literally sit as a judge', 'This refers to a future female ruler', 'The queen of the south was from Rome', 'a', 'Luke 11:31 — "The queen of the south shall rise up in the judgment with the men of this generation, and condemn them: for she came from the utmost parts of the earth to hear the wisdom of Solomon; and, behold, a greater than Solomon is here."'),
('Luke', 11, 'adults', 8, 'What does Jesus'' accusation that the Pharisees "build the sepulchres of the prophets" mean?', 'They honour dead prophets while persecuting living ones — by building tombs for prophets their fathers killed, they complete their fathers'' work and consent to the same pattern of rejecting God''s messengers', 'Jesus was criticising funeral customs', 'Building tombs was a righteous act', 'The Pharisees truly honoured the prophets', 'a', 'Luke 11:47-48 — "Woe unto you! for ye build the sepulchres of the prophets, and your fathers killed them. Truly ye bear witness that ye allow the deeds of your fathers: for they indeed killed them, and ye build their sepulchres." Honouring dead prophets while rejecting living ones exposes hypocrisy.');

-- ═══ Luke Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 12, 'kids', 1, 'What did God say to the rich man who built bigger barns to store his grain?', 'Thou fool, this night thy soul shall be required of thee', 'Well done, you are very clever', 'Build even bigger barns', 'Share some with your friends', 'a', 'Luke 12:20 — "But God said unto him, Thou fool, this night thy soul shall be required of thee: then whose shall those things be, which thou hast provided?"'),
('Luke', 12, 'kids', 2, 'What did Jesus say about sparrows and how much God cares for us?', 'You are worth more than many sparrows — God knows and cares for every one of them, and He cares even more for you', 'Sparrows are more important than people', 'God does not care about birds', 'Only eagles matter to God', 'a', 'Luke 12:6-7 — "Are not five sparrows sold for two farthings, and not one of them is forgotten before God? ... Fear not therefore: ye are of more value than many sparrows."'),
('Luke', 12, 'kids', 3, 'Where did Jesus say our treasure should be?', 'In heaven, where no thief comes near and no moth destroys', 'In a bank on earth', 'Buried in the backyard', 'In a treasure chest at home', 'a', 'Luke 12:33-34 — "Provide yourselves bags which wax not old, a treasure in the heavens that faileth not, where no thief approacheth, neither moth corrupteth. For where your treasure is, there will your heart be also."'),
-- Teens
('Luke', 12, 'teens', 1, 'What did Jesus warn about the leaven (yeast) of the Pharisees?', 'Beware of the leaven of the Pharisees, which is hypocrisy — their false outward religion spreads like yeast through dough', 'The Pharisees made excellent bread', 'Yeast is always good and useful', 'The Pharisees were honest people', 'a', 'Luke 12:1 — "Beware ye of the leaven of the Pharisees, which is hypocrisy."'),
('Luke', 12, 'teens', 2, 'What did Jesus say about covetousness?', 'Take heed, and beware of covetousness: for a man''s life consisteth not in the abundance of the things which he possesseth', 'Having many possessions makes you happy', 'The more you own, the better your life', 'Wealth always shows God''s approval', 'a', 'Luke 12:15 — "And he said unto them, Take heed, and beware of covetousness: for a man''s life consisteth not in the abundance of the things which he possesseth."'),
('Luke', 12, 'teens', 3, 'What did Jesus say about worry and the lilies of the field?', 'Consider the lilies how they grow: they toil not, they spin not; and yet Solomon in all his glory was not arrayed like one of these — if God clothes the grass, He will clothe you', 'We should worry about clothes all the time', 'Only rich people can stop worrying', 'Lilies are better than people', 'a', 'Luke 12:27 — "Consider the lilies how they grow: they toil not, they spin not; and yet I say unto you, that Solomon in all his glory was not arrayed like one of these."'),
('Luke', 12, 'teens', 4, 'What did Jesus say about being ready for His return?', 'Be ye therefore ready also: for the Son of man cometh at an hour when ye think not', 'There is no need to be ready yet', 'Only the disciples need to be ready', 'Jesus will announce His return in advance', 'a', 'Luke 12:40 — "Be ye therefore ready also: for the Son of man cometh at an hour when ye think not."'),
('Luke', 12, 'teens', 5, 'What principle did Jesus teach about responsibility?', 'For unto whomsoever much is given, of him shall be much required — greater privilege brings greater accountability', 'Those who have more can do whatever they want', 'Responsibility decreases with more gifts', 'Only leaders are held accountable', 'a', 'Luke 12:48 — "For unto whomsoever much is given, of him shall be much required: and to whom men have committed much, of him they will ask the more."'),
-- Adults
('Luke', 12, 'adults', 1, 'What does the parable of the Rich Fool teach about the relationship between wealth and security?', 'Material wealth provides no security before God — the man''s soul was required that very night, exposing the folly of storing up treasures for self while being "not rich toward God"', 'Wealth guarantees a long and happy life', 'Building bigger barns is always wise', 'God approves of all wealthy people', 'a', 'Luke 12:20-21 — "Thou fool, this night thy soul shall be required of thee... So is he that layeth up treasure for himself, and is not rich toward God." The parable exposes the illusion that material security equals existential security.'),
('Luke', 12, 'adults', 2, 'What does "where your treasure is, there will your heart be also" reveal about the human condition?', 'Our deepest affections follow our investments — treasure placement determines heart orientation, not the reverse. Jesus teaches that we can redirect our hearts by redirecting our resources toward heavenly purposes', 'Hearts naturally go wherever they want', 'Treasure has no influence on the heart', 'This only applies to wealthy people', 'a', 'Luke 12:34 — "For where your treasure is, there will your heart be also." Jesus does not say "where your heart is, there your treasure will be" — He says treasure leads the heart. Strategic generosity reorients affection.'),
('Luke', 12, 'adults', 3, 'What does "Fear not, little flock; for it is your Father''s good pleasure to give you the kingdom" reveal about God''s disposition?', 'Despite the disciples'' smallness and vulnerability, God delights in giving them the kingdom — the contrast between "little flock" and the grandeur of "the kingdom" shows that God''s grace is lavish and His purposes are not limited by human weakness', 'The kingdom is only for large groups', 'God reluctantly gives the kingdom', 'The flock must earn the kingdom', 'a', 'Luke 12:32 — "Fear not, little flock; for it is your Father''s good pleasure to give you the kingdom." The tender diminutive "little flock" combined with the Father''s "good pleasure" (eudokia) reveals gracious divine generosity.'),
('Luke', 12, 'adults', 4, 'What does Jesus'' statement about bringing "not peace, but division" mean in context?', 'The gospel inevitably creates division even within families — allegiance to Christ may conflict with family loyalty, not because Jesus seeks conflict but because His claims demand a response that splits households along lines of faith and unbelief', 'Jesus promotes family conflict', 'Christianity should never cause any disagreement', 'Division only happens among strangers', 'a', 'Luke 12:51-53 — "Suppose ye that I am come to give peace on earth? I tell you, Nay; but rather division: For from henceforth there shall be five in one house divided, three against two, and two against three." The gospel''s absolute claims create unavoidable lines of division.'),
('Luke', 12, 'adults', 5, 'What does the faithful and wise steward parable teach about accountability in leadership?', 'Leaders who faithfully serve during the master''s absence will be rewarded with greater responsibility, while those who abuse their authority will be severely punished — privilege increases accountability', 'All leaders will be treated the same regardless', 'Only the unfaithful steward exists', 'The master will never return', 'a', 'Luke 12:42-46 — "Who then is that faithful and wise steward, whom his lord shall make ruler over his household... Blessed is that servant, whom his lord when he cometh shall find so doing." The contrast between faithful and unfaithful stewards illustrates degrees of reward and judgment.'),
('Luke', 12, 'adults', 6, 'What does "unto whomsoever much is given, of him shall be much required" establish as a principle of divine judgment?', 'Judgment is proportional to privilege — those with greater knowledge, gifts, and opportunities face stricter accountability. The servant who knew his lord''s will and did not do it is beaten with many stripes, while the ignorant servant receives fewer', 'Everyone is judged by the same standard regardless', 'Ignorance is always a valid excuse', 'Only knowledge without action is judged', 'a', 'Luke 12:47-48 — Two levels of punishment based on knowledge illustrate that culpability scales with awareness. This has implications for those who hear the gospel clearly versus those with less exposure.'),
('Luke', 12, 'adults', 7, 'What does Jesus mean by "I am come to send fire on the earth"?', 'The fire represents the refining, purifying, and dividing work of the gospel — and Jesus'' baptism refers to His impending suffering on the cross, which He is "straitened" (distressed) until it is accomplished', 'Jesus will literally set the earth on fire', 'Fire refers to military conquest', 'This passage has no deeper meaning', 'a', 'Luke 12:49-50 — "I am come to send fire on the earth; and what will I, if it be already kindled? But I have a baptism to be baptized with; and how am I straitened till it be accomplished!" Fire represents judgment/purification, and the "baptism" is His passion.'),
('Luke', 12, 'adults', 8, 'What does Jesus'' rebuke about discerning the weather but not "this time" imply?', 'The religious leaders could interpret natural signs (clouds from the west mean rain, south wind means heat) but wilfully refused to read the spiritual signs of the times — the Messiah was in their midst and they could not or would not recognise Him', 'Jesus was teaching meteorology', 'Only weather experts could understand', 'The people had no access to spiritual information', 'a', 'Luke 12:54-56 — "Ye hypocrites, ye can discern the face of the sky and of the earth; but how is it that ye do not discern this time?" The charge of hypocrisy implies wilful blindness rather than inability — they chose not to see.');
